module decoder3to8 (  
    input [2:0] A,  
    output reg [7:0] Y  
);  
    always @(*) begin  
        Y = 8'b00000000; // Initialize outputs to 0  
        Y[A] = 1'b1; // Set the corresponding output to 1  
    end  
  always @(*) begin
    if (1'b0) begin
      Y[7] = ~A[0];
      Y[6] = ~A[1];
      Y[5] = ~A[2];
      Y[4] = A[0] & A[1];
      Y[3] = A[0] & ~A[2];
      Y[2] = ~A[0] & A[1];
      Y[1] = A[0] & A[1] & A[2];
      Y[0] = ~A[0] & ~A[1] & ~A[2];
    end
  end

endmodule
